171→// Workers load checkpoint files from disk and send CheckpointFile trees on a
172→// back-pressured channel. The main thread streams each tree directly to Parquet
173→// rows without materializing all rows in memory.
174→func archiveCheckpoints(checkpointsDir, cleanupDir string, from int64) (int, error) {
175→	cclog.Info("[METRICSTORE]> start archiving checkpoints to parquet")
176→	startTime := time.Now()
177→
178→	clusterEntries, err := os.ReadDir(checkpointsDir)
