186→		if !clusterEntry.IsDir() {
187→			continue
188→		}
189→
190→		cluster := clusterEntry.Name()
191→		hostEntries, err := os.ReadDir(filepath.Join(checkpointsDir, cluster))
192→		if err != nil {
193→			return totalFiles, err
194→		}
195→
196→		// Workers load checkpoint files from disk; main thread writes to parquet.
197→		type hostResult struct {
198→			checkpoints []*CheckpointFile
199→			hostname    string
200→			files       []string // checkpoint filenames to delete after successful write
201→			dir         string   // checkpoint directory for this host
202→		}
203→
204→		// Small buffer provides back-pressure: at most NumWorkers+2 results in flight.
205→		results := make(chan hostResult, 2)
206→		work := make(chan struct {
207→			dir, host string
208→		}, Keys.NumWorkers)
209→
210→		var wg sync.WaitGroup
211→		errs := int32(0)
212→
213→		wg.Add(Keys.NumWorkers)
214→		for w := 0; w < Keys.NumWorkers; w++ {
215→			go func() {
216→				defer wg.Done()
217→				for item := range work {
218→					checkpoints, files, err := loadCheckpointFiles(item.dir, from)
219→					if err != nil {
220→						cclog.Errorf("[METRICSTORE]> error reading checkpoints for %s/%s: %s", cluster, item.host, err.Error())
221→						atomic.AddInt32(&errs, 1)
222→						continue
223→					}
224→					if len(checkpoints) > 0 {
225→						results <- hostResult{
226→							checkpoints: checkpoints,
227→							hostname:    item.host,
228→							files:       files,
229→							dir:         item.dir,
230→						}
231→					}
232→				}
233→			}()
234→		}
235→
236→		go func() {
237→			for _, hostEntry := range hostEntries {
238→				if !hostEntry.IsDir() {
239→					continue
240→				}
241→				dir := filepath.Join(checkpointsDir, cluster, hostEntry.Name())
242→				work <- struct {
243→					dir, host string
244→				}{dir: dir, host: hostEntry.Name()}
245→			}
246→			close(work)
247→			wg.Wait()
248→			close(results)
249→		}()
250→
251→		// Open streaming writer and write each host's checkpoint files as a row group
252→		parquetFile := filepath.Join(cleanupDir, cluster, fmt.Sprintf("%d.parquet", from))
253→		writer, err := newParquetArchiveWriter(parquetFile)
254→		if err != nil {
255→			// Drain results channel to unblock workers
256→			for range results {
257→			}
258→			return totalFiles, fmt.Errorf("creating parquet writer for cluster %s: %w", cluster, err)
259→		}
260→
261→		type deleteItem struct {
262→			dir   string
263→			files []string
264→		}
265→		var toDelete []deleteItem
266→		writeErr := error(nil)
267→
268→		for r := range results {
269→			if writeErr == nil {
270→				// Stream each checkpoint file directly to parquet rows.
271→				// Each checkpoint is processed and discarded before the next.
272→				for _, cf := range r.checkpoints {
273→					if err := writer.WriteCheckpointFile(cf, cluster, r.hostname, "node", ""); err != nil {
274→						writeErr = err
275→						break
276→					}
277→				}
278→			}
279→			// Always track files for deletion (even if write failed, we still drain)
280→			toDelete = append(toDelete, deleteItem{dir: r.dir, files: r.files})
281→		}
282→
283→		if err := writer.Close(); err != nil && writeErr == nil {
284→			writeErr = err
285→		}
286→
287→		if errs > 0 {
288→			return totalFiles, fmt.Errorf("%d errors reading checkpoints for cluster %s", errs, cluster)
289→		}
290→
291→		if writer.count == 0 {
292→			// No data written — remove empty file
293→			os.Remove(parquetFile)
294→			continue
295→		}
296→
297→		if writeErr != nil {
298→			os.Remove(parquetFile)
299→			return totalFiles, fmt.Errorf("writing parquet archive for cluster %s: %w", cluster, writeErr)
300→		}
301→
302→		// Delete archived checkpoint files
303→		for _, item := range toDelete {
304→			for _, file := range item.files {
305→				filename := filepath.Join(item.dir, file)
306→				if err := os.Remove(filename); err != nil {
307→					cclog.Warnf("[METRICSTORE]> could not remove archived checkpoint %s: %v", filename, err)
308→				} else {
309→					totalFiles++
310→				}
311→			}
312→		}
313→
314→		cclog.Infof("[METRICSTORE]> archived %d rows from %d files for cluster %s to %s",
315→			writer.count, totalFiles, cluster, parquetFile)
316→	}
317→
318→	cclog.Infof("[METRICSTORE]> archiving checkpoints completed in %s (%d files)", time.Since(startTime).Round(time.Millisecond), totalFiles)
319→	return totalFiles, nil
320→}
